    public function run(): void
    {
        /*
         * IMPORTANT:
         * This seeder writes the large JSON columns in separate compact updates.
         * That prevents XAMPP/MySQL from throwing "MySQL server has gone away"
         * when max_allowed_packet is low.
         */
        $now = now();

        DB::table('module_library_items')->updateOrInsert(
            ['module_code' => 'PYTHON-BASIC-V3'],
            [
                'module_no' => 1,
                'title' => 'Basics of Python Programming',
                'year_level' => 'Year 1',
                'version_no' => 3,
                'version_name' => 'Python Applied Problem Solving',
                'version_code' => 'V3',
                'description' => 'A detailed third version of Python Fundamentals focused on applied problem solving, data-oriented beginner tasks, code organization, robust debugging, and readiness for data science programming.',
                'estimated_minutes' => 600,
                'sort_order' => 3,
                'is_active' => true,
                'created_at' => $now,
                'updated_at' => $now,
            ]
        );

        DB::table('module_library_items')
            ->where('module_code', 'PYTHON-BASIC-V3')
            ->update([
                'content_sections' => json_encode($this->contentSections(), JSON_UNESCAPED_UNICODE),
                'updated_at' => now(),
            ]);

        DB::table('module_library_items')
            ->where('module_code', 'PYTHON-BASIC-V3')
            ->update([
                'mcq_questions' => json_encode($this->mcqQuestions(), JSON_UNESCAPED_UNICODE),
                'updated_at' => now(),
            ]);
    }

